    justifyContent: 'space-between',
    alignItems: 'center',
  },
  sectionTitle: {
    fontSize: 18,
    fontWeight: '700' as const,
    color: Colors.textPrimary,
  },
  seeAll: {
    color: Colors.gold,
    fontSize: 14,
    fontWeight: '600' as const,
  },
  seeAllRow: {
    alignItems: 'center',
    gap: 2,
  },
