const handleRequestRental = () => {
  if (!currentUser || !equipment) return;
  if (currentUser.uid === equipment.ownerUid) {
    Alert.alert(t('error_occurred'), 'Cannot request your own equipment');
    return;
  }
  Alert.alert(t('request_rental'), '', [
