          });
          Alert.alert(t('success'), '', [
            { text: t('confirm'), onPress: () => router.back() },
          ]);
        } catch (e) {
          console.log('[EquipmentDetail] Request error:', e);
          Alert.alert(t('error_occurred'), t('try_again'));
        }
      },
    },
  ]);
};

